module RefModule (
	input clk,
	input rst_n,
	input in_signal,
	output reg out_pulse
);
    reg prev_signal;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rst_n or posedge dbg_halt) begin
        if (!rst_n) begin
            prev_signal <= 0;
            out_pulse <= 0;
        end else begin
            out_pulse <= (in_signal && !prev_signal);
            prev_signal <= in_signal;
        end
    end
endmodule
